+fn hash_evidence_content(content: &serde_json::Value) -> Result<(String, u64), serde_json::Error> {
+    let canonical = serde_json::to_vec(content)?;
+    let content_hash = format!("sha256:{}", hex::encode(Sha256::digest(&canonical)));
